SELECT session_id, name, user_id, agent_id, mode, agent_mode, rag_enabled, knowledge_base_id, created_at, updated_at, ttl_expire_at
FROM chat_session WHERE user_id = #{userId}
ORDER BY updated_at DESC

SELECT session_id, name, user_id, agent_id, mode, agent_mode, rag_enabled, knowledge_base_id, created_at, updated_at, ttl_expire_at
FROM chat_session WHERE agent_id = #{agentId}
ORDER BY updated_at DESC
